body.script:
function loadSite() {
  var input = document.getElementById("url").value;

  if (!input.startsWith("http")) {
    input = "https://" + input;
  }

  // encode URL like your old system
  var encoded = encodeURIComponent(input);

  // load through jsdelivr path
  document.getElementById("frame").src =
    "https://cdn.jsdelivr.net/gh/rok574/ixledufvms@main/scramjet/" + encoded;
}
